import modal
from collections import Counter

app = modal.App("batch-word-freq")
image = modal.Image.debian_slim()

@app.function(image=image)
def count_words(sentence: str) -> dict:
    words = sentence.split()
    return dict(Counter(words))

@app.local_entrypoint()
def main():
    sentences = [
        "hello world",
        "hello modal",
        "modal is great"
    ]

    results = count_words.map(sentences)

    combined_frequencies = Counter()
    for res in results:
        combined_frequencies.update(res)

    d = modal.Dict.from_name("batch-word-freq-output", create_if_missing=True)
    d["frequencies"] = dict(combined_frequencies)
    d["sentence_count"] = len(sentences)

